const gate = $('Fetch Gate Tracker').first().json[0] || {};
const mrr = $('Fetch Supplement MRR').all().map(i => i.json);
const totalMrr = mrr.reduce((sum, r) => sum + (parseFloat(r.mrr_gbp) || 0), 0);

const gate0a_kits = gate.total_kits_sold >= 50 ? '✅' : '⏳';
const gate0c_mrr  = totalMrr >= 1000 ? '✅' : '⏳';
const gate0c_subs = gate.active_sub_count >= 30 ? '✅' : '⏳';

const body = `
Andro Prime — Weekly KPI Digest
================================

KIT SALES
Total kits sold: ${gate.total_kits_sold || 0}

FOUNDING-MEMBER LIST
List opt-ins (non-cash): ${gate.fm_list_optins || 0}

SUPPLEMENTS
Active subscribers: ${gate.active_sub_count || 0}
MRR: £${totalMrr.toFixed(2)}

${mrr.map(r => `  ${r.product_slug}: ${r.active_subscribers} subs = £${parseFloat(r.mrr_gbp).toFixed(2)}/mo`).join('\n')}

CONVERSION
Kit 2/3 → supplement: ${gate.kit23_to_sub_conversion_pct || '—'}%

GATE STATUS
Gate 0A — 50 kits:    ${gate0a_kits} ${gate.total_kits_sold || 0}/50
Gate 0A — 25 supplement pre-orders: (tracked outside this digest)
Gate 0C — MRR £1k:    ${gate0c_mrr} £${totalMrr.toFixed(0)}/£1000
Gate 0C — 30 subs:    ${gate0c_subs} ${gate.active_sub_count || 0}/30
`.trim();

return [{ json: { subject: `Andro Prime KPI — w/c ${new Date().toLocaleDateString('en-GB')}`, body } }];
